0, 255, 0.1);\n    color: #5ec4e6;\n    border: 1px solid rgba(0, 180, 255, 0.2);\n}\n.tag-threat-低级 {\n    background: rgba(100, 200, 100, 0.1);\n    color: #6cc96c;\n    border: 1px solid rgba(100, 200, 100, 0.2);\n}\n.tag-threat-中级 {\n    background: rgba(220, 180, 50, 0.1);\n    color: #d4b438;\n    border: 1px solid rgba(220, 180, 50, 0.2);\n}\n.tag-threat-高级 {\n    background: rgba(240, 100, 50, 0.1);\n    color: #e07040;\n    border: 1px solid rgba(240, 100, 50, 0.2);\n}\n.tag-threat-领主级 {\n    background: rgba(200, 50, 80, 0.15);\n    color: #e04060;\n    border: 1px solid rgba(200, 50, 80, 0.25);\n    box-shadow: 0 0 8px rgba(224, 64, 96, 0.3);\n}\n.tag-threat-未知 {\n    background: rgba(150, 150, 150, 0.1);\n    color: #888;\n    border: 1px solid rgba(150, 150, 150, 0.2);\n}\n\n.intel-row-detail {\n    display: flex;\n    gap: 16px;\n    padding-left: 60px;\n}\n.intel-meta {\n    color: #3a758c;\n    font-size: 11px;\n    flex-shrink: 0;\n    min-width: 140px;\n    line-height: 1.6;\n}\n.meta-icon {\n    display: inline-block;\n    width: 16px;\n    text-align: center;\n    color: #4a8ea8;\n    margin-right: 2px;\n}\n.intel-desc {\n    color: #7cb3c7;\n    font-size: 12px;\n    line-height: 1.6;\n    flex: 1;\n    background: rgba(0, 150, 255, 0.03);\n    padding: 6px 10px;\n    border-radius: 4px;\n    border-left: 2px solid rgba(0, 150, 255, 0.15);\n}\n\n.intel-footer {\n    padding: 10px 18px;\n    background: rgba(0, 10, 20, 0.8);\n    border-top: 1px solid rgba(0, 200, 255, 0.15);\n    display: flex;\n    align-items: center;\n    flex-shrink: 0;\n    gap: 12px;\n}\n.intel-stat-title {\n    color: #4a8ea8;\n    font-size: 11px;\n    font-weight: 600;\n}\n.intel-stat {\n    color: #3a758c;\n    font-size: 11px;\n    letter-spacing: 0.5px;\n    display: flex;\n    gap: 12px;\n}\n:deep(.stat-item) {\n    display: flex;\n    align-items: center;\n    gap: 4px;\n}\n:deep(.stat-num) {\n    color: #5ec4e6;\n    font-family: 'Consolas', monospace;\n    font-size: 13px;\n    font-weight: 600;\n}\n</style>\n"],"sourceRoot":""}]);
